737	static void foreach_function(const json & tools, const std::function<void(const json &)> & fn) {
738	    for (const auto & tool : tools) {
739	        if (!tool.contains("type") || tool.at("type") != "function" || !tool.contains("function")) {
740	            LOG_INF("Skipping tool without function: %s", tool.dump(2).c_str());
741	            continue;
742	        }
743	        fn(tool);
744	    }
745	}
